INSERT INTO passage_questions (id, passage_id, question_number, question_type, question_text, explanation, correct_choice) VALUES
(7, 3, 1, 'comprehension', 'What lesson does the passage draw from the One Laptop per Child project?', '第4段落で、One Laptop per Childプロジェクトは、ハードウェアの提供だけでは教育成果の改善に不十分であり、教師研修や技術サポート、文化的に適切なコンテンツが必要であるという教訓を残したと述べられている。選択肢3がこの教訓を正確に反映している。', 3),
(8, 3, 2, 'fill_in_blank', 'Which of the following best fits in the blank [BLANK] in paragraph 3?', '第3段落はCOVID-19パンデミック中のデジタル格差について述べている。4億6,300万人の子どもがリモート学習にアクセスできなかったという数字が「laid bare the [BLANK]」（～を白日の下にさらした）と続くため、教育におけるデジタルアクセスの深刻な不平等の程度を意味する選択肢4が最適。', 4),
(9, 3, 3, 'comprehension', 'Which of the following best describes the author''s overall argument about technology in education?', '本文全体を通じて、著者は技術の教育における可能性を認めつつも、インフラ整備、教師研修、文化的に適切なコンテンツを含む包括的なアプローチなしには格差を拡大させるだけだと主張している。選択肢2がこの立場を最も正確に表している。', 2);
INSERT INTO question_choices (question_id, choice_number, choice_text) VALUES
(7, 1, 'Low-cost devices are the most effective way to improve educational outcomes in developing nations.'),
(7, 2, 'Private-sector involvement in education initiatives inevitably leads to commercial exploitation.'),
(7, 3, 'Providing technology alone is insufficient without supporting infrastructure, training, and relevant content.'),
(7, 4, 'Developing countries should prioritize traditional classroom instruction over digital learning.'),
(8, 1, 'success of international cooperation in addressing educational challenges during a global crisis'),
(8, 2, 'resilience of modern education systems in adapting to unexpected disruptions'),
(8, 3, 'superiority of remote learning over traditional classroom-based instruction'),
(8, 4, 'profound inequities in digital access that undermine the promise of technology-driven educational equality'),
(9, 1, 'Technology has definitively proven to be the most important factor in improving global education.'),
(9, 2, 'Technology has great potential but requires a comprehensive support system to genuinely promote educational equity.'),
(9, 3, 'Developing countries should reject digital technology and focus solely on traditional teaching methods.'),
(9, 4, 'The digital divide is an inevitable consequence of economic inequality and cannot be meaningfully addressed.');
